function scoped(scope, handler) {
	if (scope === '') return handler;

	return (req, res, next) => {
		if (req.url?.startsWith(scope)) {
			const original_url = req.url;
			req.url = req.url.slice(scope.length);
			handler(req, res, () => {
				req.url = original_url;
				next();
			});
		} else {
			next();
		}
	};
}

export function has_children(content, is_svelte_5_plus) {
	return (
		content.includes('<slot') ||
		(is_svelte_5_plus &&
			(content.includes('{@render') ||
				// children may be forwarded to a child component as a prop
				content.includes('{children}') ||
				content.includes('children={')))
	);
}

export function disableScrollHandling() {
	if (!BROWSER) {
		throw new Error('Cannot call disableScrollHandling() on the server');
	}

	if (DEV && started && !updating) {
		throw new Error('Can only disable scroll handling during navigation');
	}

	if (updating || !started) {
		autoscroll = false;
	}
}

(id, payload) => {
	const entries = this.#cache_map.get(id);
	const entry = entries?.get(payload);
	if (!entry) return;

	this.#destroy_resource?.(entry.resource);
	entry.cleanup();
	entries?.delete(payload);
	if (entries && entries.size === 0) {
		this.#cache_map.delete(id);
	}
}

destroy() {
	if (typeof window !== 'undefined') {
		window.removeEventListener('online', this.#on_online);
		window.removeEventListener('offline', this.#on_offline);
		window.removeEventListener('pagehide', this.#on_pagehide);
		window.removeEventListener('beforeunload', this.#on_pagehide);
		window.removeEventListener('pageshow', this.#on_pageshow);
	}

	this.#fan_out.done();

	void this.#interrupt?.();
}

set(value) {
	this.#ready = true;
	this.#loading = false;
	this.#error = undefined;
	this.#raw = value;

	if (this.#resolve_first) {
		this.#resolve_first();
		this.#resolve_first = null;
		this.#reject_first = null;
	} else {
		this.#promise = Promise.resolve();
	}

	this.#fan_out.push(value);
}

function validate_link_option(element, name, value) {
	if (value === null) return;

	// @ts-expect-error - includes is dumb
	if (!warned.has(element) && !valid_link_options[name].includes(value)) {
		console.error(
			`Unexpected value for ${name} — should be one of ${valid_link_options[name]
				.map((option) => JSON.stringify(option))
				.join(', ')}`,
			element
		);

		warned.add(element);
	}
}

export function set_nested_value(object, path_string, value) {
	if (path_string.startsWith('n:')) {
		path_string = path_string.slice(2);
		value = value === '' ? undefined : parseFloat(value);
	} else if (path_string.startsWith('b:')) {
		path_string = path_string.slice(2);
		value = value === 'on';
	}

	deep_set(object, split_path(path_string), value);
}

function reverse_endianness(bytes) {
	for (let i = 0; i < bytes.length; i += 4) {
		const a = bytes[i + 0];
		const b = bytes[i + 1];
		const c = bytes[i + 2];
		const d = bytes[i + 3];

		bytes[i + 0] = d;
		bytes[i + 1] = c;
		bytes[i + 2] = b;
		bytes[i + 3] = a;
	}
}

export async function resolve_route(resolved_path, url, manifest) {
	if (!manifest._.client.routes) {
		return text('Server-side route resolution disabled', { status: 400 });
	}

	const matchers = await manifest._.matchers();
	const result = find_route(resolved_path, manifest._.client.routes, matchers);

	return create_server_routing_response(result?.route ?? null, result?.params ?? {}, url, manifest)
		.response;
}

export function load_page_nodes(page, manifest) {
	return Promise.all([
		// we use == here rather than === because [undefined] serializes as "[null]"
		...page.layouts.map((n) => (n == undefined ? n : manifest._.nodes[n]())),
		manifest._.nodes[page.leaf]()
	]);
}

function propagate_context(fn) {
	return async (req, ...rest) => {
		if (otel === null) {
			return fn(req, ...rest);
		}

		const { propagation, context } = await otel;
		const c = propagation.extract(context.active(), Object.fromEntries(req.headers));
		return context.with(c, async () => {
			return await fn(req, ...rest);
		});
	};
}

export function validate_load_response(data, location_description) {
	if (data != null && Object.getPrototypeOf(data) !== Object.prototype) {
		throw new Error(
			`a load function ${location_description} returned ${
				typeof data !== 'object'
					? `a ${typeof data}`
					: data instanceof Response
						? 'a Response object'
						: Array.isArray(data)
							? 'an array'
							: 'a non-plain object'
			}, but must return a plain object at the top level (i.e. \`return {...}\`)`
		);
	}
}

export function base64_decode(encoded) {
	// Using `Buffer` is faster than iterating
	if (!BROWSER && globalThis.Buffer) {
		const buffer = globalThis.Buffer.from(encoded, 'base64');
		return new Uint8Array(buffer);
	}

	const binary = atob(encoded);
	const bytes = new Uint8Array(binary.length);

	for (let i = 0; i < binary.length; i++) {
		bytes[i] = binary.charCodeAt(i);
	}

	return bytes;
}

export function escape_html(str, is_attr) {
	const dict = is_attr ? escape_html_attr_dict : escape_html_dict;
	const escaped_str = str.replace(is_attr ? escape_html_attr_regex : escape_html_regex, (match) => {
		if (match.length === 2) {
			// valid surrogate pair
			return match;
		}

		return dict[match] ?? `&#${match.charCodeAt(0)};`;
	});

	return escaped_str;
}

export function mkdirp(dir) {
	try {
		fs.mkdirSync(dir, { recursive: true });
	} catch (/** @type {any} */ e) {
		if (e.code === 'EEXIST') {
			if (!fs.statSync(dir).isDirectory()) {
				throw new Error(`Cannot create directory ${dir}, a file already exists at this position`, {
					cause: e
				});
			}
			return;
		}
		throw e;
	}
}

validate() {
	for (const layout of this.layouts()) {
		if (layout) {
			validate_layout_server_exports(layout.server, /** @type {string} */ (layout.server_id));
			validate_layout_exports(layout.universal, /** @type {string} */ (layout.universal_id));
		}
	}

	const page = this.page();
	if (page) {
		validate_page_server_exports(page.server, /** @type {string} */ (page.server_id));
		validate_page_exports(page.universal, /** @type {string} */ (page.universal_id));
	}
}

export function resolve(base, path) {
	// special case
	if (path[0] === '/' && path[1] === '/') return path;

	let url = new URL(base, internal);
	url = new URL(path, url);

	return url.protocol === internal.protocol ? url.pathname + url.search + url.hash : url.href;
}

export function detect_features(bundle_files) {
	const { program, checker } = build_program(bundle_files);
	const flagged = new Set();
	for (const file of bundle_files) {
		const source = program.getSourceFile(file);
		if (!source) continue;
		walk_source(source, checker, (id) => flagged.add(id));
	}
	return flagged;
}

TSParameterProperty(node, context) {
	if ((node.readonly || node.accessibility) && context.path.at(-2)?.kind === 'constructor') {
		e.typescript_invalid_feature(node, 'accessibility modifiers on constructor parameters');
	}
	return context.visit(node.parameter);
}

function is_valid_element_name(name) {
	// DOCTYPE (e.g. !DOCTYPE)
	if (regex_doctype_name.test(name)) return true;
	// svelte:* meta tags (e.g. svelte:element, svelte:head)
	if (regex_namespaced_name.test(name)) return true;
	// standard HTML/SVG/MathML elements and custom elements
	return REGEX_VALID_TAG_NAME.test(name);
}

function collect_transitive_dependencies(binding, bindings) {
	if (bindings.has(binding)) {
		return;
	}
	bindings.add(binding);

	if (binding.kind === 'legacy_reactive') {
		for (const dep of binding.legacy_dependencies) {
			collect_transitive_dependencies(dep, bindings);
		}
	}
}
